16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.JsonNode;
19	import com.fasterxml.jackson.databind.ObjectMapper;
20	import jakarta.inject.Inject;
21	import jakarta.inject.Singleton;
22	import java.io.IOException;
23	import java.nio.file.Files;
24	import java.nio.file.Path;
25	import java.util.ArrayList;
26	import java.util.Comparator;
27	import java.util.List;
28	import java.util.Map;
29	import java.util.Optional;
30	import java.util.stream.Stream;
31	
32	/**
33	 * Gathers a source's sessions — each session's normalized timeline steps plus any cached AI analysis
34	 * — for the cross-session features ({@link InsightsService}, {@code MinerService}). Antigravity is
35	 * read directly from {@code ~/.gemini/<flavor>/brain}; other sources go through their
36	 * {@link SessionSource}.
37	 *
38	 * <p>The scan is capped at the most recent {@link #MAX_SESSIONS} sessions so callers stay responsive
39	 * even for very large histories; {@link Collected#totalSessionCount()} still reports the true total.
40	 */
41	@Singleton
42	public class SessionCollector {
43	
44	    static final int MAX_SESSIONS = 150;
45	
46	    private static final ObjectMapper MAPPER = new ObjectMapper();
47	
48	    private final List<SessionSource> sources;
49	
50	    @Inject
51	    public SessionCollector(List<SessionSource> sources) {
52	        this.sources = sources;
53	    }
54	
55	    /** The gathered sessions for a flavor and the true total (which may exceed the sampled size). */
56	    public record Collected(int totalSessionCount, List<FleetInsights.Session> sessions) {}
57	
58	    public Collected collect(String flavor) throws IOException {
59	        Optional<SessionSource> source = sources
60	            .stream()
61	            .filter(s -> s.handles(flavor))
62	            .findFirst();
63	        return source.isPresent() ? fromSource(source.get()) : fromAntigravity(flavor);
64	    }
65	
66	    private Collected fromSource(SessionSource source) throws IOException {
67	        List<Map<String, String>> conversations = source.listConversations();
68	        List<FleetInsights.Session> sessions = new ArrayList<>();
69	        for (Map<String, String> info : conversations) {
70	            if (sessions.size() >= MAX_SESSIONS) break;
71	            String id = info.get("id");
72	            List<JsonNode> steps = parseArray(source.transcriptJson(id));
73	            JsonNode summary = source.cachedSummary(id).map(this::parseJson).orElse(null);
74	            sessions.add(new FleetInsights.Session(id, steps, summary));
75	        }
76	        return new Collected(conversations.size(), sessions);
77	    }
78	
79	    private Collected fromAntigravity(String flavor) throws IOException {
80	        Path brain = AntigravityPaths.brainDir(flavor);
81	        if (!Files.isDirectory(brain)) {
82	            return new Collected(0, List.of());
83	        }
84	
85	        List<Path> dirs;
86	        try (Stream<Path> paths = Files.list(brain)) {
87	            dirs =
88	                paths
89	                    .filter(Files::isDirectory)
90	                    .filter(d -> transcriptOf(d) != null)
91	                    .sorted(Comparator.comparingLong(this::lastModified).reversed())
92	                    .toList();
93	        }
94	
95	        List<FleetInsights.Session> sessions = new ArrayList<>();
96	        for (Path dir : dirs) {
97	            if (sessions.size() >= MAX_SESSIONS) break;
98	            Path transcript = readableTranscript(dir);
99	            if (transcript == null) continue;
100	            try {
101	                List<JsonNode> steps = parseLines(Files.readAllLines(transcript));
102	                JsonNode summary = readJson(
103	                    AntigravityPaths.summaryJson(AntigravityPaths.logsDir(dir))
104	                );
105	                sessions.add(
106	                    new FleetInsights.Session(dir.getFileName().toString(), steps, summary)
107	                );
108	            } catch (IOException e) {
109	                // A session may be deleted/rotated mid-scan; skip it rather than failing the report.
110	            }
111	        }
112	        return new Collected(dirs.size(), sessions);
113	    }
114	
115	    // A session is listed (and sorted) by its transcript.jsonl, mirroring BrainController.list.
116	    private Path transcriptOf(Path sessionDir) {
117	        return nonEmpty(AntigravityPaths.transcript(AntigravityPaths.logsDir(sessionDir)));
118	    }
119	
120	    // For reading, prefer transcript_full.jsonl when present, mirroring BrainController.getTranscript,
121	    // so the counts match the rendered timeline.
122	    private Path readableTranscript(Path sessionDir) {
123	        Path logs = AntigravityPaths.logsDir(sessionDir);
124	        Path full = nonEmpty(AntigravityPaths.transcriptFull(logs));
125	        return full != null ? full : nonEmpty(AntigravityPaths.transcript(logs));
126	    }
127	
128	    private Path nonEmpty(Path file) {
129	        try {
130	            return (Files.exists(file) && Files.size(file) > 0) ? file : null;
131	        } catch (IOException e) {
132	            return null;
133	        }
134	    }
135	
136	    private long lastModified(Path sessionDir) {
137	        Path transcript = transcriptOf(sessionDir);
138	        if (transcript == null) return 0L;
139	        try {
140	            return Files.getLastModifiedTime(transcript).toMillis();
141	        } catch (Exception e) {
142	            return 0L;
143	        }
144	    }
145	
146	    private List<JsonNode> parseArray(String jsonArray) {
147	        List<JsonNode> steps = new ArrayList<>();
148	        try {
149	            JsonNode arr = MAPPER.readTree(jsonArray);
150	            if (arr.isArray()) arr.forEach(steps::add);
151	        } catch (Exception e) {
152	            // ignore malformed transcript
153	        }
154	        return steps;
155	    }
156	
157	    private List<JsonNode> parseLines(List<String> lines) {
158	        List<JsonNode> steps = new ArrayList<>();
159	        for (String line : lines) {
160	            if (line == null || line.isBlank()) continue;
161	            try {
162	                steps.add(MAPPER.readTree(line));
163	            } catch (Exception e) {
164	                // skip malformed line
165	            }
166	        }
167	        return steps;
168	    }
169	
170	    private JsonNode parseJson(String json) {
171	        try {
172	            return MAPPER.readTree(json);
173	        } catch (Exception e) {
174	            return null;
175	        }
176	    }
177	
178	    private JsonNode readJson(Path path) {
179	        try {
180	            return Files.exists(path) ? MAPPER.readTree(Files.readString(path)) : null;
181	        } catch (Exception e) {
182	            return null;
183	        }
184	    }
185	}
