16	package io.github.glaforge.agybrainviz;
17	
18	import java.io.IOException;
19	import java.nio.file.Files;
20	import java.nio.file.Path;
21	import java.util.Optional;
22	
23	/**
24	 * On-disk cache for analysis summaries of an external session source, stored in a tool-owned
25	 * directory as {@code <id>.summary.json} (and an optional {@code <id>.short_title.txt}). Cache file
26	 * paths are resolved with a traversal guard since the id originates from a request path variable.
27	 */
28	final class SummaryCache {
29	
30	    private final Path dir;
31	
32	    SummaryCache(Path dir) {
33	        this.dir = dir;
34	    }
35	
36	    Optional<String> read(String id) throws IOException {
37	        Path file = file(id, ".summary.json");
38	        return Files.exists(file) ? Optional.of(Files.readString(file)) : Optional.empty();
39	    }
40	
41	    void delete(String id) throws IOException {
42	        Files.deleteIfExists(file(id, ".summary.json"));
43	        Files.deleteIfExists(file(id, ".short_title.txt"));
44	    }
45	
46	    void write(String id, String summaryJson, String title) throws IOException {
47	        Files.createDirectories(dir);
48	        Files.writeString(file(id, ".summary.json"), summaryJson);
49	        // The short title is best-effort and must not fail the summary cache write.
50	        if (title != null && !title.isBlank()) {
51	            try {
52	                Files.writeString(file(id, ".short_title.txt"), title.trim());
53	            } catch (IOException ignore) {}
54	        }
55	    }
56	
57	    private Path file(String id, String suffix) {
58	        Path base = dir.normalize();
59	        Path file = base.resolve(id + suffix).normalize();
60	        if (!file.startsWith(base)) {
61	            throw new IllegalArgumentException("Invalid session id: " + id);
62	        }
63	        return file;
64	    }
65	}
