16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.JsonNode;
19	import com.fasterxml.jackson.databind.ObjectMapper;
20	import com.fasterxml.jackson.databind.node.ArrayNode;
21	import com.fasterxml.jackson.databind.node.ObjectNode;
22	import java.util.ArrayList;
23	import java.util.List;
24	import java.util.Optional;
25	
26	/**
27	 * Adapts a Claude Code session transcript (JSONL under {@code ~/.claude/projects/<dir>/<uuid>.jsonl})
28	 * into the step schema the frontend timeline understands (the same shape used for Antigravity and
29	 * Codex).
30	 *
31	 * <p>Each line is {@code {type, message, timestamp, ...}}. Conversation lines are {@code user} and
32	 * {@code assistant}; a {@code user} message carries either a plain string (the human prompt) or an
33	 * array of {@code tool_result} blocks (results sent back to the model), while an {@code assistant}
34	 * message carries an array of {@code text} / {@code thinking} / {@code tool_use} blocks. Other line
35	 * types ({@code attachment}, {@code system}, {@code summary}, {@code pr-link}, ...) are not part of
36	 * the rendered timeline, though a {@code summary} line (or the first user prompt) yields the title.
37	 */
38	final class ClaudeCodeAdapter {
39	
40	    private ClaudeCodeAdapter() {}
41	
42	    private static final ObjectMapper MAPPER = new ObjectMapper();
43	
44	    static String toTranscriptJson(List<String> lines) {
45	        try {
46	            return MAPPER.writeValueAsString(toSteps(lines));
47	        } catch (Exception e) {
48	            return "[]";
49	        }
50	    }
51	
52	    static List<ObjectNode> toSteps(List<String> lines) {
53	        List<ObjectNode> steps = new ArrayList<>();
54	        for (String line : lines) {
55	            if (line == null || line.isBlank()) continue;
56	            try {
57	                JsonNode root = MAPPER.readTree(line);
58	                String type = root.path("type").asText("");
59	                String ts = root.path("timestamp").asText("");
60	                JsonNode content = root.path("message").path("content");
61	                if ("user".equals(type)) {
62	                    addUserSteps(steps, content, ts);
63	                } else if ("assistant".equals(type)) {
64	                    addAssistantSteps(steps, content, ts);
65	                }
66	            } catch (Exception e) {
67	                // skip malformed lines
68	            }
69	        }
70	        return steps;
71	    }
72	
73	    private static void addUserSteps(List<ObjectNode> steps, JsonNode content, String ts) {
74	        if (content.isTextual()) {
75	            String text = content.asText();
76	            if (text.isBlank()) return;
77	            ObjectNode step = newStep(ts);
78	            step.put("type", "USER_INPUT");
79	            step.put("source", "USER_EXPLICIT");
80	            step.put("content", text);
81	            steps.add(step);
82	            return;
83	        }
84	        if (content.isArray()) {
85	            for (JsonNode block : content) {
86	                if (!"tool_result".equals(block.path("type").asText(""))) continue;
87	                String text = textOf(block.path("content"));
88	                if (text.isBlank()) continue;
89	                ObjectNode step = newStep(ts);
90	                step.put("type", "FUNCTION_OUTPUT");
91	                step.put("source", "TOOL");
92	                step.put("content", text);
93	                if (block.path("is_error").asBoolean(false)) {
94	                    step.put("status", "ERROR");
95	                }
96	                steps.add(step);
97	            }
98	        }
99	    }
100	
101	    private static void addAssistantSteps(List<ObjectNode> steps, JsonNode content, String ts) {
102	        if (!content.isArray()) return;
103	        for (JsonNode block : content) {
104	            switch (block.path("type").asText("")) {
105	                case "text":
106	                    {
107	                        String text = block.path("text").asText("");
108	                        if (text.isBlank()) break;
109	                        ObjectNode step = newStep(ts);
110	                        step.put("type", "MESSAGE");
111	                        step.put("source", "MODEL");
112	                        step.put("content", text);
113	                        steps.add(step);
114	                        break;
115	                    }
116	                case "thinking":
117	                    {
118	                        String text = block.path("thinking").asText("");
119	                        if (text.isBlank()) break;
120	                        ObjectNode step = newStep(ts);
121	                        step.put("type", "REASONING");
122	                        step.put("source", "MODEL");
123	                        step.put("thinking", text);
124	                        steps.add(step);
125	                        break;
126	                    }
127	                case "tool_use":
128	                    {
129	                        ObjectNode step = newStep(ts);
130	                        step.put("type", "FUNCTION_CALL");
131	                        step.put("source", "MODEL");
132	                        ArrayNode toolCalls = step.putArray("tool_calls");
133	                        ObjectNode tool = toolCalls.addObject();
134	                        tool.put("name", block.path("name").asText("unknown"));
135	                        tool.set(
136	                            "args",
137	                            block.has("input") ? block.get("input") : MAPPER.createObjectNode()
138	                        );
139	                        steps.add(step);
140	                        break;
141	                    }
142	                default:
143	                    break;
144	            }
145	        }
146	    }
147	
148	    static List<List<String>> toAnalysisSequences(List<String> lines) {
149	        return NormalizedSteps.toAnalysisSequences(toSteps(lines));
150	    }
151	
152	    /**
153	     * Derives a short session title from a {@code summary} line if present, otherwise the first
154	     * human prompt (a {@code user} line with string content).
155	     *
156	     * @param lines the raw JSONL lines of a Claude Code session
157	     * @return the derived summary text, if any
158	     */
159	    static Optional<String> deriveSummary(List<String> lines) {
160	        String fallback = null;
161	        for (String line : lines) {
162	            if (line == null || line.isBlank()) continue;
163	            try {
164	                JsonNode root = MAPPER.readTree(line);
165	                String type = root.path("type").asText("");
166	                if ("summary".equals(type)) {
167	                    String s = root.path("summary").asText("");
168	                    if (!s.isBlank()) return Optional.of(summarize(s));
169	                } else if (fallback == null && "user".equals(type)) {
170	                    JsonNode content = root.path("message").path("content");
171	                    if (content.isTextual() && !content.asText().isBlank()) {
172	                        fallback = summarize(content.asText());
173	                    }
174	                }
175	            } catch (Exception e) {
176	                // skip malformed lines
177	            }
178	        }
179	        return Optional.ofNullable(fallback);
180	    }
181	
182	    private static ObjectNode newStep(String ts) {
183	        ObjectNode step = MAPPER.createObjectNode();
184	        if (ts != null && !ts.isBlank()) step.put("created_at", ts);
185	        return step;
186	    }
187	
188	    // Tool-result content is either a plain string or an array of {type:"text", text:...} blocks.
189	    private static String textOf(JsonNode content) {
190	        if (content == null || content.isNull() || content.isMissingNode()) return "";
191	        if (content.isTextual()) return content.asText();
192	        if (content.isArray()) {
193	            StringBuilder sb = new StringBuilder();
194	            for (JsonNode part : content) {
195	                JsonNode text = part.get("text");
196	                if (text != null && text.isTextual()) {
197	                    if (sb.length() > 0) sb.append("\n");
198	                    sb.append(text.asText());
199	                }
200	            }
201	            return sb.toString();
202	        }
203	        return content.toString();
204	    }
205	
206	    private static String summarize(String text) {
207	        String trimmed = text.strip();
208	        return trimmed.length() > 80 ? trimmed.substring(0, 80) + "..." : trimmed;
209	    }
210	}
