28	/**
29	 * Reads configuration from a {@code .env} file in the process's <em>current working directory</em>, so
30	 * the app can be configured without exporting shell variables (works for {@code gradlew run}, the fat
31	 * jar, and the native executable alike).
32	 *
33	 * <p>Real environment variables always take precedence over the file: callers consult
34	 * {@code System.getenv} first and fall back to {@link #get(String)}. Loading can be turned off with
35	 * {@code -Ddotenv.enabled=false} (the test and e2e runs do this, so a developer's local {@code .env}
36	 * can never change test behaviour), and the path overridden with {@code -Ddotenv.path=...}.
37	 *
38	 * <p>Format: {@code KEY=VALUE} per line. Blank lines and {@code #} comment lines are ignored, an
39	 * {@code export } prefix is tolerated, surrounding single/double quotes are stripped, and for
40	 * unquoted values a trailing {@code # comment} is dropped.
41	 */
42	final class DotEnv {
43	
44	    private DotEnv() {}
45	
46	    private static final String ENABLED_PROPERTY = "dotenv.enabled";
47	    private static final String PATH_PROPERTY = "dotenv.path";
48	    private static final Pattern EXPORT_PREFIX = Pattern.compile("^export\\s+");
49	
50	    private static volatile Map<String, String> cached;
51	
52	    /** Whether {@code .env} loading is active (default true; disabled in tests via a system property). */
53	    static boolean enabled() {
