121	    private static String cleanValue(String value) {
122	        if (!value.isEmpty()) {
123	            char quote = value.charAt(0);
124	            if (quote == '"' || quote == '\'') {
125	                int close = value.indexOf(quote, 1);
126	                // A quoted value is taken verbatim (it may contain '#' or spaces); anything after the
127	                // closing quote — typically an inline comment — is discarded.
128	                if (close > 0) return value.substring(1, close);
129	            }
130	        }
131	        // Unquoted: drop a trailing inline comment.
132	        int comment = value.indexOf(" #");
133	        return (comment >= 0 ? value.substring(0, comment) : value).strip();
