    void aStoreIsConfiguredUnlessTheUrlIsDeliberatelyBlanked() {
        assertTrue(config(null, null, null, null).isConfigured());
        assertTrue(config("jdbc:postgresql://host/db", null, null, null).isConfigured());
    }

    @Test
    void theIngestTokenIsAbsentUntilItIsSet() {
        assertEquals(Optional.empty(), config(null, null, null, null).ingestToken());
        assertEquals(Optional.empty(), config(null, null, null, "   ").ingestToken());
        assertEquals(Optional.of("t0ken"), config(null, null, null, "t0ken").ingestToken());
    }

    @Test
    void theNotConfiguredMessagePointsAtDockerCompose() {
        assertFalse(config(null, null, null, null).notConfiguredMessage().isBlank());
        assertTrue(
            config(null, null, null, null).notConfiguredMessage().contains("docker compose up")
        );
    }
}

