17	
18	import com.fasterxml.jackson.databind.JsonNode;
19	import com.fasterxml.jackson.databind.ObjectMapper;
20	import java.util.ArrayList;
21	import java.util.List;
22	import java.util.function.ToIntFunction;
23	
24	/**
25	 * Pure transcript-processing helpers used by {@link AnalysisController}.
26	 *
27	 * <p>This logic is intentionally free of any I/O, network, or framework dependencies so it can be
28	 * unit-tested directly: it turns raw JSONL transcript lines into condensed, de-duplicated
29	 * "sequences" of human-readable summary lines, and splits those lines into chunks that fit within a
30	 * token budget.
31	 */
32	final class TranscriptParser {
33	
34	    private TranscriptParser() {}
35	
36	    /**
37	     * Condenses raw JSONL transcript lines into a list of sequences. A new sequence is started at
38	     * every user input; within a sequence, agent tool calls and error/exception events are
39	     * summarized into compact single lines. Each returned sequence has consecutive duplicate lines
40	     * collapsed (see {@link #deduplicateSequence(List)}). Blank and malformed lines are skipped.
41	     *
42	     * @param allLines the raw JSONL lines of a transcript
43	     * @return one list of summary lines per user-initiated sequence
44	     */
45	    static List<List<String>> parseSequences(List<String> allLines) {
46	        ObjectMapper mapper = new ObjectMapper();
47	        List<List<String>> sequences = new ArrayList<>();
48	        List<String> currentSequence = new ArrayList<>();
49	
50	        for (String line : allLines) {
51	            if (line.trim().isEmpty()) continue;
52	            try {
53	                JsonNode node = mapper.readTree(line);
54	                String type = node.path("type").asText("");
55	                if (
56	                    "USER_INPUT".equals(type) ||
57	                    "USER_EXPLICIT".equals(node.path("source").asText(""))
58	                ) {
59	                    if (!currentSequence.isEmpty()) {
60	                        sequences.add(deduplicateSequence(currentSequence));
61	                        currentSequence = new ArrayList<>();
62	                    }
63	                    String content = node.path("content").asText("");
64	                    currentSequence.add(
65	                        "USER REQUEST: " + content.substring(0, Math.min(2000, content.length()))
66	                    );
67	                } else if (
68	                    "PLANNER_RESPONSE".equals(type) ||
69	                    "MODEL".equals(node.path("source").asText(""))
70	                ) {
71	                    JsonNode tools = node.path("tool_calls");
72	                    if (!tools.isMissingNode() && tools.isArray()) {
73	                        for (JsonNode tool : tools) {
74	                            String name = tool.path("name").asText("unknown");
75	                            String action = tool.path("arguments").path("toolAction").asText("");
76	                            String tgt = tool.path("arguments").path("TargetFile").asText("");
77	                            if (tgt.isEmpty()) tgt =
78	                                tool.path("arguments").path("CommandLine").asText("");
79	                            currentSequence.add(
80	                                "AGENT ACTION: [" + name + "] " + action + " -> " + tgt
81	                            );
82	                        }
83	                    }
84	                } else if (
85	                    node.has("error") ||
86	                    (node.has("content") && node.path("content").asText("").contains("Exception"))
87	                ) {
88	                    String err = node.path("content").asText("");
89	                    currentSequence.add(
90	                        "SYSTEM EVENT/ERROR: " + err.substring(0, Math.min(500, err.length()))
91	                    );
92	                }
93	            } catch (Exception e) {
94	                // skip malformed
95	            }
96	        }
97	        if (!currentSequence.isEmpty()) {
98	            sequences.add(deduplicateSequence(currentSequence));
99	        }
100	        return sequences;
101	    }
102	
103	    /**
104	     * Collapses runs of identical consecutive lines into a single line annotated with the repeat
105	     * count, e.g. {@code "foo (repeated 3 times)"}. Non-consecutive duplicates are left intact.
106	     *
107	     * @param sequence the lines to de-duplicate
108	     * @return a new list with consecutive duplicates collapsed
109	     */
110	    static List<String> deduplicateSequence(List<String> sequence) {
111	        if (sequence.isEmpty()) return sequence;
112	        List<String> deduped = new ArrayList<>();
113	        String lastLine = null;
114	        int count = 0;
115	        for (String line : sequence) {
116	            if (line.equals(lastLine)) {
117	                count++;
118	            } else {
119	                if (count > 1) {
120	                    deduped.set(deduped.size() - 1, lastLine + " (repeated " + count + " times)");
121	                }
122	                deduped.add(line);
123	                lastLine = line;
124	                count = 1;
125	            }
126	        }
127	        if (count > 1) {
128	            deduped.set(deduped.size() - 1, lastLine + " (repeated " + count + " times)");
129	        }
130	        return deduped;
131	    }
132	
133	    /**
134	     * Recursively splits {@code lines} into chunks whose joined text stays within {@code maxTokens},
135	     * appending each resulting chunk to {@code safeChunks}. A chunk of a single line is never split
136	     * further, even if it exceeds the budget. If {@code tokenCounter} throws, a character-length
137	     * heuristic ({@code length / 2}) is used as a fallback estimate.
138	     *
139	     * @param lines the lines to split
140	     * @param tokenCounter estimates the token count of a string
141	     * @param maxTokens the maximum tokens allowed per chunk
142	     * @param safeChunks output accumulator that receives the produced chunks
143	     */
144	    static void splitIntoSafeChunks(
145	        List<String> lines,
146	        ToIntFunction<String> tokenCounter,
147	        int maxTokens,
148	        List<List<String>> safeChunks
149	    ) {
150	        if (lines.isEmpty()) return;
151	        String text = String.join("\n", lines);
152	        try {
153	            int tokens = tokenCounter.applyAsInt(text);
154	            if (tokens <= maxTokens || lines.size() == 1) {
155	                safeChunks.add(lines);
156	            } else {
157	                int mid = lines.size() / 2;
158	                splitIntoSafeChunks(lines.subList(0, mid), tokenCounter, maxTokens, safeChunks);
159	                splitIntoSafeChunks(
160	                    lines.subList(mid, lines.size()),
161	                    tokenCounter,
162	                    maxTokens,
163	                    safeChunks
164	                );
165	            }
166	        } catch (Exception e) {
167	            int fallbackTokens = text.length() / 2;
168	            if (fallbackTokens <= maxTokens || lines.size() == 1) {
169	                safeChunks.add(lines);
170	            } else {
171	                int mid = lines.size() / 2;
172	                splitIntoSafeChunks(lines.subList(0, mid), tokenCounter, maxTokens, safeChunks);
173	                splitIntoSafeChunks(
174	                    lines.subList(mid, lines.size()),
175	                    tokenCounter,
176	                    maxTokens,
177	                    safeChunks
178	                );
179	            }
180	        }
181	    }
