432	    @Test
433	    void summarizeReportsAlreadyRunningForAConcurrentRequest() throws Exception {
434	        String id = "concurrent-session";
435	        writeTranscript(id, "{\"type\":\"USER_INPUT\",\"content\":\"go\"}\n");
436	
437	        // Note: this test assumes the IO executor is the default unbounded/cached pool — request #1
438	        // holds one thread on f.get(), its chunk task holds a second on the release latch, and
439	        // request #2 needs a third. If the IO pool is ever pinned to a small fixed size this would
440	        // block until the 10s latch timeout rather than asserting cleanly.
441	        CountDownLatch started = new CountDownLatch(1);
442	        CountDownLatch release = new CountDownLatch(1);
443	        ANALYZE_STARTED.set(started);
444	        ANALYZE_RELEASE.set(release);
445	
446	        ExecutorService background = Executors.newSingleThreadExecutor();
447	        try {
448	            Future<String> first = background.submit(() ->
449	                get("/api/analysis/conversations/" + id + "/summarize?force=true")
450	            );
451	            // Wait until the first request is inside analyze() and holding the per-id lock.
452	            assertTrue(started.await(5, TimeUnit.SECONDS), "first analysis did not start");
453	
454	            String second = get("/api/analysis/conversations/" + id + "/summarize?force=true");
455	            assertTrue(
456	                second.contains("already running"),
457	                "concurrent request should be rejected, got: " + second
458	            );
459	
460	            release.countDown();
461	            String firstResult = first.get(10, TimeUnit.SECONDS);
462	            assertTrue(firstResult.contains("chunk summary"));
463	        } finally {
464	            release.countDown();
465	            background.shutdownNow();
466	        }
467	    }
