// Transcripts can be large, so a request is bounded by cumulative raw bytes, well under the server's
// request-size limit — a fixed session count alone could easily blow past it.
const maxBatchBytes = 16 << 20 // 16 MiB

// chunk groups sessions into requests, flushing when the next session would exceed either the count
// cap or the byte budget. A single session larger than the budget is sent alone rather than dropped.
func chunk(sessions []client.PushSession, maxCount, maxBytes int) [][]client.PushSession {
	var batches [][]client.PushSession
	var current []client.PushSession
	currentBytes := 0
	for _, s := range sessions {
		size := len(s.Raw)
		if len(current) > 0 && (len(current) >= maxCount || currentBytes+size > maxBytes) {
			batches = append(batches, current)
			current = nil
			currentBytes = 0
		}
		current = append(current, s)
		currentBytes += size
	}
	if len(current) > 0 {
		batches = append(batches, current)
	}
	return batches
}

