15	// Package scan locates an agent tool's local transcripts and turns each into a
16	// stable, hashed Session ready to push. It deliberately does not parse the
17	// transcript formats — the server normalizes them — so the CLI never has to
18	// track how Antigravity, Codex, or Claude Code lay out their steps.
19	package scan
20	
21	import (
22		"crypto/sha256"
23		"encoding/hex"
24		"fmt"
25		"io/fs"
26		"os"
27		"path/filepath"
28		"slices"
29		"sort"
30		"strings"
31	)
32	
33	// Source names, which are also the `source` the server stores each session under.
34	const (
35		SourceAntigravityCLI = "antigravity-cli"
36		SourceAntigravityIDE = "antigravity-ide"
37		SourceCodex          = "codex"
38		SourceClaudeCode     = "claude-code"
39	)
40	
41	// AllSources is every source the CLI knows how to scan, in listing order.
42	var AllSources = []string{SourceAntigravityCLI, SourceAntigravityIDE, SourceCodex, SourceClaudeCode}
43	
44	// Tool-owned cache directory this CLI's server writes next to a source's
45	// sessions; it holds summaries, never transcripts, so never descend into it.
46	const cacheDir = ".agybrainviz"
47	
48	// Session is one local trajectory, ready to push. Title is intentionally left
49	// empty: the server derives a consistent title from the transcript.
50	type Session struct {
51		Source string
52		ID     string
53		Mtime  int64 // file modification time, epoch milliseconds
54		Raw    string
55		Hash   string // hex SHA-256 of Raw, matching the server's content hash
56	}
57	
58	// Sha256Hex returns the lowercase hex SHA-256 of s, byte-for-byte identical to
59	// the server's hash of the same raw transcript.
60	func Sha256Hex(s string) string {
61		sum := sha256.Sum256([]byte(s))
62		return hex.EncodeToString(sum[:])
63	}
64	
65	// Scan collects the sessions for the requested sources under home. A source
66	// whose directory is absent contributes nothing; an unknown source is an error.
67	func Scan(home string, sources []string) ([]Session, error) {
68		var out []Session
69		for _, source := range sources {
70			var (
71				sessions []Session
72				err      error
73			)
74			switch source {
75			case SourceClaudeCode:
76				sessions, err = scanFlat(source, filepath.Join(home, ".claude", "projects"))
77			case SourceCodex:
78				sessions, err = scanFlat(source, filepath.Join(home, ".codex", "sessions"))
79			case SourceAntigravityCLI, SourceAntigravityIDE:
80				sessions, err = scanAntigravity(source, filepath.Join(home, ".gemini", source, "brain"))
81			default:
82				return nil, fmt.Errorf("unknown source %q (known: %s)", source, strings.Join(AllSources, ", "))
83			}
84			if err != nil {
85				return nil, fmt.Errorf("scanning %s: %w", source, err)
86			}
87			out = append(out, sessions...)
88		}
89		return out, nil
90	}
91	
92	// scanFlat walks a tree of `<id>.jsonl` files (Codex, Claude Code), taking the
93	// id from the filename stem — never from the path, so the same session
94	// de-duplicates no matter which machine or project directory produced it.
95	func scanFlat(source, root string) ([]Session, error) {
96		if !isDir(root) {
97			return nil, nil
98		}
99		var sessions []Session
100		err := filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
101			if err != nil {
102				// An unreadable directory or entry must not abort syncing the machine;
103				// skip it and carry on with what is readable.
104				if d != nil && d.IsDir() {
105					return fs.SkipDir
106				}
107				return nil
108			}
109			if d.IsDir() {
110				if d.Name() == cacheDir {
111					return fs.SkipDir
112				}
113				return nil
114			}
115			if !strings.HasSuffix(d.Name(), ".jsonl") {
116				return nil
117			}
118			session, ok, err := readSession(source, strings.TrimSuffix(d.Name(), ".jsonl"), path)
119			if err != nil {
120				return nil // skip an unreadable transcript rather than failing the source
121			}
122			if ok {
123				sessions = append(sessions, session)
124			}
125			return nil
126		})
127		if err != nil {
128			return nil, err
129		}
130		return sessions, nil
131	}
132	
133	// scanAntigravity lists the session directories under a flavor's brain and reads
134	// each one's transcript, preferring transcript_full.jsonl when present (the
135	// richer capture) exactly as the server does. The id is the directory name.
136	func scanAntigravity(source, brain string) ([]Session, error) {
137		if !isDir(brain) {
138			return nil, nil
139		}
140		entries, err := os.ReadDir(brain)
141		if err != nil {
142			return nil, err
143		}
144		var sessions []Session
145		for _, entry := range entries {
146			if !entry.IsDir() {
147				continue
148			}
149			logs := filepath.Join(brain, entry.Name(), ".system_generated", "logs")
150			transcript := firstExisting(
151				filepath.Join(logs, "transcript_full.jsonl"),
152				filepath.Join(logs, "transcript.jsonl"),
153			)
154			if transcript == "" {
155				continue
156			}
157			session, ok, err := readSession(source, entry.Name(), transcript)
158			if err != nil {
159				continue // skip an unreadable transcript rather than failing the source
160			}
161			if ok {
162				sessions = append(sessions, session)
163			}
164		}
165		return sessions, nil
166	}
167	
168	// readSession reads one transcript into a hashed Session, reporting ok=false for
169	// an empty file (a session that never really started, which the server ignores).
170	func readSession(source, id, path string) (Session, bool, error) {
171		info, err := os.Stat(path)
172		if err != nil {
173			return Session{}, false, err
174		}
175		if info.Size() == 0 {
176			return Session{}, false, nil
177		}
178		raw, err := os.ReadFile(path)
179		if err != nil {
180			return Session{}, false, err
181		}
182		if len(raw) == 0 {
183			return Session{}, false, nil
184		}
185		// Send and hash the UTF-8-coerced content the server will actually store. JSON
186		// transport replaces invalid bytes with U+FFFD, so hashing the raw bytes would
187		// diverge from the server's hash and re-upload the session on every run.
188		content := strings.ToValidUTF8(string(raw), "�")
189		return Session{
190			Source: source,
191			ID:     id,
192			Mtime:  info.ModTime().UnixMilli(),
193			Raw:    content,
194			Hash:   Sha256Hex(content),
195		}, true, nil
196	}
197	
198	func firstExisting(paths ...string) string {
199		for _, p := range paths {
200			if info, err := os.Stat(p); err == nil && !info.IsDir() {
201				return p
202			}
203		}
204		return ""
205	}
206	
207	func isDir(path string) bool {
208		info, err := os.Stat(path)
209		return err == nil && info.IsDir()
210	}
211	
212	// Validate reports the first unknown source name, if any.
213	func Validate(sources []string) error {
214		for _, s := range sources {
215			if !slices.Contains(AllSources, s) {
216				return fmt.Errorf("unknown source %q (known: %s)", s, strings.Join(AllSources, ", "))
217			}
218		}
219		return nil
220	}
221	
222	// SortedByKey returns sessions ordered by source then id, for stable output.
223	func SortedByKey(sessions []Session) []Session {
224		out := slices.Clone(sessions)
225		sort.Slice(out, func(i, j int) bool {
226			if out[i].Source != out[j].Source {
227				return out[i].Source < out[j].Source
228			}
229			return out[i].ID < out[j].ID
230		})
231		return out
232	}
