15	// Package client talks to the visualizer's /api/ingest endpoints: it reads a
16	// source's manifest and pushes batches of trajectories.
17	package client
18	
19	import (
20		"bytes"
21		"context"
22		"encoding/json"
23		"fmt"
24		"io"
25		"net/http"
26		"net/url"
27		"strings"
28		"time"
29	)
30	
31	// Client is a thin HTTP client for the ingest API. An empty token leaves requests
32	// unauthenticated, which the server accepts when INGEST_TOKEN is unset.
33	type Client struct {
34		baseURL string
35		token   string
36		http    *http.Client
37	}
38	
39	// New returns a Client for baseURL, sending a bearer token when one is given.
40	func New(baseURL, token string) *Client {
41		return &Client{
42			baseURL: strings.TrimRight(baseURL, "/"),
43			token:   token,
44			// A finite timeout so a wedged server fails the sync instead of hanging it.
45			http: &http.Client{Timeout: 60 * time.Second},
46		}
47	}
48	
49	// PushSession mirrors the server's IngestSession record; the JSON field names
50	// must match it exactly or the server deserializes nulls and rejects the batch.
51	type PushSession struct {
52		Source      string `json:"source"`
53		ID          string `json:"id"`
54		Title       string `json:"title,omitempty"`
55		SourceMtime int64  `json:"sourceMtime"`
56		Raw         string `json:"raw"`
57	}
58	
59	// Result mirrors the server's IngestResult.
60	type Result struct {
61		Ingested int `json:"ingested"`
62		Skipped  int `json:"skipped"`
63		Failed   int `json:"failed"`
64	}
65	
66	// Manifest returns the server's id -> contentHash map for a source, so the
67	// caller can push only what changed.
68	func (c *Client) Manifest(ctx context.Context, source string) (map[string]string, error) {
69		u := c.baseURL + "/api/ingest/manifest?source=" + url.QueryEscape(source)
70		req, err := http.NewRequestWithContext(ctx, http.MethodGet, u, nil)
71		if err != nil {
72			return nil, err
73		}
74		var manifest map[string]string
75		if err := c.do(req, &manifest); err != nil {
76			return nil, fmt.Errorf("fetching manifest for %s: %w", source, err)
77		}
78		return manifest, nil
79	}
80	
81	// Push uploads a batch of trajectories and returns the server's tally.
82	func (c *Client) Push(ctx context.Context, sessions []PushSession) (Result, error) {
83		payload, err := json.Marshal(sessions)
84		if err != nil {
85			return Result{}, err
86		}
87		req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.baseURL+"/api/ingest/sessions", bytes.NewReader(payload))
88		if err != nil {
89			return Result{}, err
90		}
91		req.Header.Set("Content-Type", "application/json")
92	
93		var result Result
94		if err := c.do(req, &result); err != nil {
95			return Result{}, fmt.Errorf("pushing %d session(s): %w", len(sessions), err)
96		}
97		return result, nil
98	}
99	
100	// do sends the request, adds auth, treats any non-2xx as an error (never a
101	// silent empty result), and decodes a successful body into out.
102	func (c *Client) do(req *http.Request, out any) error {
103		if c.token != "" {
104			req.Header.Set("Authorization", "Bearer "+c.token)
105		}
106		resp, err := c.http.Do(req)
107		if err != nil {
108			// Name the target and hint at the cause; the bare net/http error ("dial
109			// tcp …: connection refused") doesn't say what to do about it.
110			return fmt.Errorf("cannot reach the visualizer at %s (is it running? check --server): %w", c.baseURL, err)
111		}
112		defer resp.Body.Close()
113	
114		body, readErr := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
115		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
116			// Report the status even if the body read was partial.
117			return fmt.Errorf("%s returned %d: %s", req.URL.Path, resp.StatusCode, serverMessage(body, resp.Status))
118		}
119		if readErr != nil {
120			return fmt.Errorf("reading %s response: %w", req.URL.Path, readErr)
121		}
122		if out == nil {
123			return nil
124		}
125		if err := json.Unmarshal(body, out); err != nil {
126			return fmt.Errorf("decoding %s response: %w", req.URL.Path, err)
127		}
128		return nil
129	}
130	
131	// serverMessage prefers the API's {"error": "..."} text, falling back to the
132	// HTTP status line, so a failure reads as a cause rather than a bare code.
133	func serverMessage(body []byte, status string) string {
134		var envelope struct {
135			Error string `json:"error"`
136		}
137		if json.Unmarshal(body, &envelope) == nil && envelope.Error != "" {
138			return envelope.Error
139		}
140		if len(body) > 0 {
141			return strings.TrimSpace(string(body))
142		}
143		return status
144	}
