// summarySuffix appends the standalone-summary tally to a report line, but only when there is one, so
// the common no-summary case reads exactly as before.
func summarySuffix(n int, dryRun bool) string {
	if n == 0 {
		return ""
	}
	if dryRun {
		return fmt.Sprintf(", %d summary(ies) would sync", n)
	}
	return fmt.Sprintf(", %d summary(ies) synced", n)
}

